# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.
# Category: insecure_deep_linking

package com.example.myapp.deeplink

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import android.widget.Toast

class DeepLinkHandlerActivity : AppCompatActivity() {

    companion object {
        const val SCHEME = "myapp"
        const val HOST_PROFILE = "profile"
        const val HOST_PAYMENT = "payment"
        const val PATH_CONFIRM = "confirm"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        handleDeepLink(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleDeepLink(it) }
    }

    private fun handleDeepLink(intent: Intent) {
        val data: Uri? = intent.data

        if (data == null) {
            showError("Invalid deep link")
            finish()
            return
        }

        if (data.scheme != SCHEME) {
            showError("Invalid scheme: ${data.scheme}")
            finish()
            return
        }

        when (data.host) {
            HOST_PROFILE -> handleProfileDeepLink(data)
            HOST_PAYMENT -> handlePaymentDeepLink(data)
            else -> {
                showError("Unknown host: ${data.host}")
                finish()
            }
        }
    }

    private fun handleProfileDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        
        if (pathSegments.isEmpty()) {
            showError("Profile ID is required")
            finish()
            return
        }

        val profileId = pathSegments[0]
        
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra("PROFILE_ID", profileId)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        
        startActivity(intent)
        finish()
    }

    private fun handlePaymentDeepLink(uri: Uri) {
        val pathSegments = uri.pathSegments
        
        if (pathSegments.isEmpty()) {
            showError("Payment action is required")
            finish()
            return
        }

        val action = pathSegments[0]
        
        when (action) {
            PATH_CONFIRM -> {
                val transactionId = uri.getQueryParameter("transaction_id")
                val amount = uri.getQueryParameter("amount")
                
                val intent = Intent(this, PaymentConfirmActivity::class.java).apply {
                    putExtra("TRANSACTION_ID", transactionId)
                    putExtra("AMOUNT", amount)
                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
                }
                
                startActivity(intent)
                finish()
            }
            else -> {
                showError("Unknown payment action: $action")
                finish()
            }
        }
    }

    private fun showError(message: String) {
        Toast.makeText(this, message, Toast.LENGTH_LONG).show()
    }
}

class ProfileActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_profile)
        
        val profileId = intent.getStringExtra("PROFILE_ID")
        
        supportActionBar?.title = "Profile: $profileId"
    }
}

class PaymentConfirmActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_payment_confirm)
        
        val transactionId = intent.getStringExtra("TRANSACTION_ID")
        val amount = intent.getStringExtra("AMOUNT")
        
        supportActionBar?.title = "Confirm Payment"
    }
}